// src/data/bookingStore.js
// Single source of truth for bookings — read/written by both guest and admin sides.

import { MOCK_BOOKINGS } from './mockBookings.js';

const STORAGE_KEY = 'mizuya_bookings';

function seedIfEmpty() {
  if (!localStorage.getItem(STORAGE_KEY)) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(MOCK_BOOKINGS));
  }
}

export function getBookings() {
  seedIfEmpty();
  try {
    return JSON.parse(localStorage.getItem(STORAGE_KEY)) || [];
  } catch {
    return [];
  }
}

export function addBooking(booking) {
  const all = getBookings();
  all.unshift(booking); // newest first
  localStorage.setItem(STORAGE_KEY, JSON.stringify(all));
}

export function updateBooking(id, patch) {
  const all = getBookings().map(b => b.id === id ? { ...b, ...patch } : b);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(all));
  return all;
}

export function generateRefCode() {
  return 'MZ-' + Math.random().toString(36).slice(2, 7).toUpperCase();
}
